#!/usr/bin/env python3
"""Apply a move plan generated by generate_move_plan.py.

Moves files according to the plan CSV.  Directories are created as needed.
Operations are logged to `move_log.csv` in the same directory as the plan.
If the target file exists, the move for that file is skipped.
"""

import argparse
import csv
import os
import shutil
import sys
from datetime import datetime


def apply_plan(plan_path: str, log_path: str):
    log_entries = []
    with open(plan_path, newline="") as f:
        reader = csv.DictReader(f)
        for row in reader:
            action = row.get("action")
            src = row.get("source_path")
            dest = row.get("target_path")
            reason = row.get("reason")
            timestamp = datetime.now().isoformat()
            status = "skipped"
            msg = ""
            if action != "move":
                msg = f"Unsupported action: {action}"
            else:
                if not os.path.exists(src):
                    msg = "source missing"
                else:
                    os.makedirs(os.path.dirname(dest), exist_ok=True)
                    if os.path.exists(dest):
                        msg = "target exists"
                    else:
                        try:
                            shutil.move(src, dest)
                            status = "moved"
                            msg = ""
                        except Exception as e:
                            msg = str(e)
                            status = "error"
            log_entries.append({
                "timestamp": timestamp,
                "action": action,
                "source_path": src,
                "target_path": dest,
                "reason": reason,
                "status": status,
                "message": msg,
            })
    # Write log
    with open(log_path, "w", newline="", encoding="utf-8-sig") as lf:
        fieldnames = ["timestamp", "action", "source_path", "target_path", "reason", "status", "message"]
        writer = csv.DictWriter(lf, fieldnames=fieldnames)
        writer.writeheader()
        for entry in log_entries:
            writer.writerow(entry)


def main() -> None:
    parser = argparse.ArgumentParser(description="Apply a move plan of duplicate files")
    parser.add_argument("--plan", required=True, help="Path to move_plan.csv")
    args = parser.parse_args()
    plan_path = os.path.abspath(args.plan)
    log_path = os.path.join(os.path.dirname(plan_path), "move_log.csv")
    apply_plan(plan_path, log_path)
    print(f"Move plan applied.  Log written to {log_path}")


if __name__ == "__main__":
    main()